type Listener = (...args: unknown[]) => void;

interface ListenerEntry {
  listener: Listener;
  once: boolean;
}

export class EventEmitter {
  private _listeners: Map<string, ListenerEntry[]> = new Map();

  // Register a persistent listener; returns an unsubscribe function
  on(event: string, listener: Listener): () => void {
    this._getOrCreate(event).push({ listener, once: false });
    return () => this.off(event, listener);
  }

  // Register a one-time listener that removes itself after the first emit
  once(event: string, listener: Listener): void {
    this._getOrCreate(event).push({ listener, once: true });
  }

  // Call all listeners for the event; returns true if any listeners existed
  emit(event: string, ...args: unknown[]): boolean {
    const entries = this._listeners.get(event);
    if (!entries || entries.length === 0) return false;

    // Snapshot before iterating so mid-emit off() calls don't corrupt iteration
    const snapshot = [...entries];
    for (const entry of snapshot) {
      if (entry.once) {
        // Remove from live array before calling to prevent double-fire on re-entrant emits
        this._removeEntry(event, entry.listener);
      }
      entry.listener(...args);
    }
    return true;
  }

  // Remove a specific listener from an event (no-op if not found)
  off(event: string, listener: Listener): void {
    this._removeEntry(event, listener);
  }

  // Remove all listeners, optionally scoped to one event
  removeAllListeners(event?: string): void {
    if (event === undefined) {
      this._listeners.clear();
    } else {
      this._listeners.delete(event);
    }
  }

  // Return the number of listeners registered for an event
  listenerCount(event: string): number {
    return this._listeners.get(event)?.length ?? 0;
  }

  // Return all event names that currently have at least one listener
  eventNames(): string[] {
    return Array.from(this._listeners.keys());
  }

  // --- Private helpers ---

  private _getOrCreate(event: string): ListenerEntry[] {
    let entries = this._listeners.get(event);
    if (!entries) {
      entries = [];
      this._listeners.set(event, entries);
    }
    return entries;
  }

  private _removeEntry(event: string, listener: Listener): void {
    const entries = this._listeners.get(event);
    if (!entries) return;
    const idx = entries.findIndex((e) => e.listener === listener);
    if (idx !== -1) {
      entries.splice(idx, 1);
    }
    // Keep eventNames() clean — remove the key when no listeners remain
    if (entries.length === 0) {
      this._listeners.delete(event);
    }
  }
}

